// Payload: { type: 'weekly_digest', stats, requested_by }
// stats = { period: { from, to }, tasks: { total, done, open, overdue, created_this_week, completed_this_week }, finance: { total, pending, approved_amount }, by_staff: [{ name, done, active, overdue }] }
const body = $input.first().json.body || {};
const stats = body.stats || {};
const tasks = stats.tasks || {};
const finance = stats.finance || {};
const byStaff = stats.by_staff || [];
const period = stats.period || {};
const requestedBy = body.requested_by || 'CEO';

const fmt = (n) => Number(n || 0).toLocaleString('mn-MN');

const staffRows = byStaff
  .sort((a, b) => (b.done || 0) - (a.done || 0))
  .map(s => `<tr><td style="padding:6px 12px;border-bottom:1px solid #eee;">${s.name || ''}</td><td style="padding:6px 12px;border-bottom:1px solid #eee;text-align:center;color:#10b981;font-weight:600;">${s.done || 0}</td><td style="padding:6px 12px;border-bottom:1px solid #eee;text-align:center;color:#3b82f6;">${s.active || 0}</td><td style="padding:6px 12px;border-bottom:1px solid #eee;text-align:center;color:#ef4444;font-weight:${(s.overdue||0)>0?'700':'400'};">${s.overdue || 0}</td></tr>`)
  .join('');

const html = `<!DOCTYPE html><html><body style="font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;color:#37352f;background:#fbfbfa;margin:0;padding:20px;">
<div style="max-width:600px;margin:0 auto;background:#fff;border-radius:12px;overflow:hidden;border:1px solid #eee;">
  <div style="background:linear-gradient(135deg,#5e6ad2,#8b5cf6);color:#fff;padding:24px;">
    <h1 style="margin:0;font-size:22px;">Долоо хоногийн тойм</h1>
    <p style="margin:6px 0 0;opacity:.9;font-size:14px;">${period.from || ''} → ${period.to || ''}</p>
  </div>
  <div style="padding:24px;">
    <h2 style="font-size:16px;margin:0 0 12px;">Ажлын тойм</h2>
    <table style="width:100%;border-collapse:collapse;margin-bottom:24px;">
      <tr><td style="padding:8px 0;color:#787774;">Нийт</td><td style="padding:8px 0;text-align:right;font-weight:700;">${fmt(tasks.total)}</td></tr>
      <tr><td style="padding:8px 0;color:#787774;border-top:1px solid #eee;">✓ Дуусгасан</td><td style="padding:8px 0;text-align:right;font-weight:700;color:#10b981;border-top:1px solid #eee;">${fmt(tasks.done)}</td></tr>
      <tr><td style="padding:8px 0;color:#787774;border-top:1px solid #eee;">Идэвхтэй</td><td style="padding:8px 0;text-align:right;font-weight:700;color:#3b82f6;border-top:1px solid #eee;">${fmt(tasks.open)}</td></tr>
      <tr><td style="padding:8px 0;color:#787774;border-top:1px solid #eee;">⚠ Хоцорсон</td><td style="padding:8px 0;text-align:right;font-weight:700;color:#ef4444;border-top:1px solid #eee;">${fmt(tasks.overdue)}</td></tr>
      <tr><td style="padding:8px 0;color:#787774;border-top:1px solid #eee;">Энэ долоо хоногт үүсгэсэн</td><td style="padding:8px 0;text-align:right;border-top:1px solid #eee;">${fmt(tasks.created_this_week)}</td></tr>
      <tr><td style="padding:8px 0;color:#787774;border-top:1px solid #eee;">Энэ долоо хоногт дуусгасан</td><td style="padding:8px 0;text-align:right;color:#10b981;font-weight:700;border-top:1px solid #eee;">${fmt(tasks.completed_this_week)}</td></tr>
    </table>

    <h2 style="font-size:16px;margin:0 0 12px;">Санхүү (сүүлийн 30 хоног)</h2>
    <table style="width:100%;border-collapse:collapse;margin-bottom:24px;">
      <tr><td style="padding:8px 0;color:#787774;">Зөвшөөрсөн дүн</td><td style="padding:8px 0;text-align:right;font-weight:700;color:#10b981;">${fmt(finance.approved_amount)}₮</td></tr>
      <tr><td style="padding:8px 0;color:#787774;border-top:1px solid #eee;">Хүлээгдэж буй</td><td style="padding:8px 0;text-align:right;color:#f59e0b;font-weight:600;border-top:1px solid #eee;">${fmt(finance.pending)}</td></tr>
      <tr><td style="padding:8px 0;color:#787774;border-top:1px solid #eee;">Нийт хүсэлт</td><td style="padding:8px 0;text-align:right;border-top:1px solid #eee;">${fmt(finance.total)}</td></tr>
    </table>

    ${staffRows ? `<h2 style="font-size:16px;margin:0 0 12px;">Ажилтны гүйцэтгэл</h2>
    <table style="width:100%;border-collapse:collapse;">
      <tr style="background:#f7f7f5;"><th style="padding:8px 12px;text-align:left;font-size:12px;text-transform:uppercase;color:#787774;">Ажилтан</th><th style="padding:8px 12px;font-size:12px;text-transform:uppercase;color:#787774;">✓</th><th style="padding:8px 12px;font-size:12px;text-transform:uppercase;color:#787774;">Идэвхтэй</th><th style="padding:8px 12px;font-size:12px;text-transform:uppercase;color:#787774;">⚠</th></tr>
      ${staffRows}
    </table>` : ''}
  </div>
  <div style="background:#f7f7f5;padding:14px 24px;text-align:center;font-size:12px;color:#787774;">Чимун ХХК · Дотоод даалгавар систем</div>
</div>
</body></html>`;

return [{ json: { to: requestedBy, subject: `Долоо хоногийн тойм · ${period.from || ''} → ${period.to || ''}`, html, period, summary: tasks } }];
